import React, { useState, useEffect } from 'react'
import { supabase } from '../../lib/supabaseClient'

const PAYMENT_METHODS = ['JazzCash', 'EasyPaisa', 'Bank Transfer', 'Cash on Delivery', 'Rocket', 'UPaisa']

// ─── Condition config ─────────────────────────────────────────────────────────
const CONDITION_CONFIG: Record<string, { color: string; bg: string; border: string; dot: string }> = {
  'New':      { color: '#4ade80', bg: 'rgba(34,197,94,0.1)',   border: 'rgba(34,197,94,0.3)',   dot: '#4ade80' },
  'Like New': { color: '#60a5fa', bg: 'rgba(59,130,246,0.1)',  border: 'rgba(59,130,246,0.3)',  dot: '#60a5fa' },
  'Good':     { color: '#c8a200', bg: 'rgba(200,162,0,0.1)',   border: 'rgba(200,162,0,0.3)',   dot: '#FFD700' },
  'Fair':     { color: '#f97316', bg: 'rgba(249,115,22,0.1)',  border: 'rgba(249,115,22,0.3)',  dot: '#f97316' },
  'Poor':     { color: '#f87171', bg: 'rgba(239,68,68,0.1)',   border: 'rgba(239,68,68,0.3)',   dot: '#ef4444' },
}
const getCond = (c: string) => CONDITION_CONFIG[c] || CONDITION_CONFIG['Good']

// ─── Shared styled input ──────────────────────────────────────────────────────
function FInput({ value, onChange, placeholder, type = 'text', required, step, min, style: extraStyle }: any) {
  const [focused, setFocused] = useState(false)
  return (
    <input
      type={type} value={value} onChange={onChange} placeholder={placeholder}
      required={required} step={step} min={min}
      onFocus={() => setFocused(true)} onBlur={() => setFocused(false)}
      style={{
        width: '100%', padding: '13px 16px', boxSizing: 'border-box',
        background: focused ? 'rgba(200,162,0,0.05)' : 'rgba(255,255,255,0.04)',
        border: `1px solid ${focused ? 'rgba(200,162,0,0.45)' : 'rgba(255,255,255,0.08)'}`,
        borderRadius: '12px', color: '#f9fafb', fontSize: '14px', fontWeight: '500',
        fontFamily: "'Inter', sans-serif", outline: 'none',
        boxShadow: focused ? '0 0 0 3px rgba(200,162,0,0.08)' : 'none',
        transition: 'all 0.22s ease', ...extraStyle,
      }}
    />
  )
}
function FTextarea({ value, onChange, placeholder, rows = 3 }: any) {
  const [focused, setFocused] = useState(false)
  return (
    <textarea
      value={value} onChange={onChange} placeholder={placeholder} rows={rows}
      onFocus={() => setFocused(true)} onBlur={() => setFocused(false)}
      style={{
        width: '100%', padding: '13px 16px', boxSizing: 'border-box',
        background: focused ? 'rgba(200,162,0,0.05)' : 'rgba(255,255,255,0.04)',
        border: `1px solid ${focused ? 'rgba(200,162,0,0.45)' : 'rgba(255,255,255,0.08)'}`,
        borderRadius: '12px', color: '#f9fafb', fontSize: '14px',
        fontFamily: "'Inter', sans-serif", outline: 'none', resize: 'vertical',
        boxShadow: focused ? '0 0 0 3px rgba(200,162,0,0.08)' : 'none',
        transition: 'all 0.22s ease',
      }}
    />
  )
}
function FSelect({ value, onChange, children }: any) {
  const [focused, setFocused] = useState(false)
  return (
    <div style={{ position: 'relative' }}>
      <select
        value={value} onChange={onChange}
        onFocus={() => setFocused(true)} onBlur={() => setFocused(false)}
        style={{
          width: '100%', padding: '13px 40px 13px 16px', boxSizing: 'border-box',
          background: focused ? 'rgba(200,162,0,0.05)' : 'rgba(255,255,255,0.04)',
          border: `1px solid ${focused ? 'rgba(200,162,0,0.45)' : 'rgba(255,255,255,0.08)'}`,
          borderRadius: '12px', color: '#f9fafb', fontSize: '14px',
          fontFamily: "'Inter', sans-serif", outline: 'none', appearance: 'none', cursor: 'pointer',
          transition: 'all 0.22s ease',
        }}
      >{children}</select>
      <svg style={{ position: 'absolute', right: 14, top: '50%', transform: 'translateY(-50%)', pointerEvents: 'none', color: '#4b5563' }}
        width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
        <polyline points="6 9 12 15 18 9"/>
      </svg>
    </div>
  )
}

// ─── Label chip ───────────────────────────────────────────────────────────────
function CondBadge({ condition }: { condition: string }) {
  const c = getCond(condition)
  return (
    <span style={{
      display: 'inline-flex', alignItems: 'center', gap: '5px',
      padding: '3px 10px', borderRadius: '99px',
      background: c.bg, border: `1px solid ${c.border}`,
      color: c.color, fontSize: '10px', fontWeight: '800',
      letterSpacing: '0.06em', textTransform: 'uppercase', fontFamily: "'Inter', sans-serif",
    }}>
      <span style={{ width: 5, height: 5, borderRadius: '50%', background: c.dot, display: 'inline-block', boxShadow: `0 0 5px ${c.dot}` }} />
      {condition}
    </span>
  )
}

// ─── Skeleton card ────────────────────────────────────────────────────────────
function SkeletonCard({ i }: { i: number }) {
  return (
    <div style={{
      background: 'rgba(12,12,18,0.9)', borderRadius: '20px',
      border: '1px solid rgba(255,255,255,0.04)', padding: '22px',
      animation: `fadeSlideUp 0.4s ease ${i * 70}ms both`,
    }}>
      {[80, 120, 60].map((w, j) => (
        <div key={j} style={{ height: 12, width: `${w}%`, maxWidth: w * 2.4,
          background: 'rgba(255,255,255,0.05)', borderRadius: 6,
          marginBottom: 12, animation: `shimmer 1.6s ease-in-out ${j * 0.2}s infinite` }} />
      ))}
      <div style={{ height: 36, background: 'rgba(200,162,0,0.05)', borderRadius: 10, marginTop: 16, animation: 'shimmer 1.6s ease-in-out 0.6s infinite' }} />
    </div>
  )
}

// ─── Product card ─────────────────────────────────────────────────────────────
function ListingCard({ item, isOwner, isBuying, onBuy, onOpen, index }: {
  item: any; isOwner: boolean; isBuying: boolean
  onBuy: (item: any) => void; onOpen: (item: any) => void; index: number
}) {
  const [hovered, setHovered] = useState(false)
  const [btnHovered, setBtnHovered] = useState(false)

  return (
    <div
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      onClick={() => onOpen(item)}
      style={{
        position: 'relative',
        background: hovered ? 'linear-gradient(135deg, rgba(24,24,32,0.98), rgba(20,18,28,0.98))' : 'rgba(12,12,18,0.92)',
        backdropFilter: 'blur(28px)', borderRadius: '20px',
        border: `1px solid ${hovered ? 'rgba(200,162,0,0.35)' : 'rgba(255,255,255,0.05)'}`,
        overflow: 'hidden', cursor: 'pointer',
        transition: 'all 0.35s cubic-bezier(0.4,0,0.2,1)',
        transform: hovered ? 'translateY(-5px)' : 'translateY(0)',
        boxShadow: hovered ? '0 24px 64px rgba(0,0,0,0.5), 0 0 0 1px rgba(200,162,0,0.06), 0 0 40px rgba(200,162,0,0.06)' : '0 4px 20px rgba(0,0,0,0.4)',
        animation: `fadeSlideUp 0.45s ease ${index * 65}ms both`,
        display: 'flex', flexDirection: 'column',
      }}
    >
      {/* Top shimmer line */}
      <div style={{
        position: 'absolute', top: 0, left: 0, right: 0, height: '1px',
        background: hovered ? 'linear-gradient(90deg, transparent, rgba(200,162,0,0.5), transparent)' : 'linear-gradient(90deg, rgba(255,255,255,0.03), transparent)',
        transition: 'all 0.35s ease',
      }} />

      {/* Category stripe */}
      {item.category && (
        <div style={{
          position: 'absolute', top: 0, left: 0, bottom: 0, width: '3px',
          background: 'linear-gradient(180deg, rgba(200,162,0,0) 0%, rgba(200,162,0,0.6) 40%, rgba(200,162,0,0.6) 60%, rgba(200,162,0,0) 100%)',
          opacity: hovered ? 1 : 0.35, transition: 'opacity 0.35s',
        }} />
      )}

      <div style={{ padding: '22px 22px 18px 26px', flex: 1, display: 'flex', flexDirection: 'column' }}>
        {/* Header: badges */}
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '12px', gap: '8px' }}>
          <CondBadge condition={item.condition} />
          {item.category && (
            <span style={{
              padding: '3px 10px', borderRadius: '99px', flexShrink: 0,
              background: 'rgba(59,130,246,0.08)', border: '1px solid rgba(59,130,246,0.2)',
              color: '#60a5fa', fontSize: '10px', fontWeight: '700',
              letterSpacing: '0.05em', fontFamily: "'Inter', sans-serif",
            }}>{item.category}</span>
          )}
        </div>

        {/* Product name */}
        <h3 style={{
          fontSize: '16px', fontWeight: '800', color: 'white',
          letterSpacing: '-0.02em', margin: '0 0 6px', lineHeight: 1.2,
          fontFamily: "'Inter', sans-serif",
          transition: 'color 0.25s',
        }}>
          {item.item_name}
        </h3>

        {/* Description */}
        {item.description && (
          <p style={{
            color: '#4b5563', fontSize: '12px', lineHeight: '1.5',
            margin: '0 0 12px', fontFamily: "'Inter', sans-serif",
            display: '-webkit-box', WebkitLineClamp: 2, WebkitBoxOrient: 'vertical', overflow: 'hidden',
          }}>
            {item.description}
          </p>
        )}

        {/* Payment methods */}
        {item.payment_methods?.length > 0 && (
          <div style={{ display: 'flex', gap: '4px', flexWrap: 'wrap', marginBottom: '14px' }}>
            {item.payment_methods.slice(0, 3).map((m: string) => (
              <span key={m} style={{
                padding: '2px 8px', borderRadius: '99px',
                background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.07)',
                color: '#4b5563', fontSize: '9px', fontWeight: '600',
                letterSpacing: '0.05em', fontFamily: "'Inter', sans-serif",
              }}>{m}</span>
            ))}
            {item.payment_methods.length > 3 && (
              <span style={{ padding: '2px 8px', borderRadius: '99px', background: 'rgba(255,255,255,0.02)', color: '#374151', fontSize: '9px', fontFamily: "'Inter', sans-serif" }}>
                +{item.payment_methods.length - 3}
              </span>
            )}
          </div>
        )}

        {/* Footer: price + buy */}
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: 'auto', paddingTop: '14px', borderTop: '1px solid rgba(255,255,255,0.04)' }}>
          <div>
            <div style={{ color: '#4b5563', fontSize: '9px', fontWeight: '700', letterSpacing: '0.1em', textTransform: 'uppercase', fontFamily: "'Inter', sans-serif", marginBottom: '2px' }}>Price</div>
            <div style={{
              fontSize: '22px', fontWeight: '900', letterSpacing: '-0.04em',
              background: 'linear-gradient(135deg, #c8a200, #FFD700)',
              WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent', backgroundClip: 'text',
              fontFamily: "'Inter', sans-serif",
            }}>
              ${Number(item.price).toFixed(2)}
            </div>
          </div>

          <button
            onMouseEnter={() => setBtnHovered(true)}
            onMouseLeave={() => setBtnHovered(false)}
            onClick={e => { e.stopPropagation(); onBuy(item) }}
            disabled={isOwner || isBuying}
            style={{
              padding: '9px 18px', borderRadius: '12px', border: 'none',
              background: isOwner
                ? 'rgba(255,255,255,0.04)'
                : isBuying
                ? 'rgba(200,162,0,0.4)'
                : btnHovered
                ? 'linear-gradient(135deg, #c8a200, #FFD700)'
                : 'linear-gradient(135deg, #b89200, #d4a500)',
              color: isOwner ? '#374151' : '#0a0a0a',
              fontSize: '12px', fontWeight: '800', letterSpacing: '0.03em',
              cursor: isOwner ? 'not-allowed' : 'pointer',
              fontFamily: "'Inter', sans-serif",
              transform: btnHovered && !isOwner && !isBuying ? 'scale(1.06) translateY(-1px)' : 'scale(1)',
              boxShadow: btnHovered && !isOwner ? '0 0 20px rgba(200,162,0,0.45), 0 4px 14px rgba(200,162,0,0.3)' : 'none',
              transition: 'all 0.25s cubic-bezier(0.4,0,0.2,1)', whiteSpace: 'nowrap',
              display: 'inline-flex', alignItems: 'center', gap: '5px',
            }}
          >
            {isOwner ? 'Your Item' : isBuying ? <><Spinner />Buying…</> : 'Buy Now'}
          </button>
        </div>
      </div>
    </div>
  )
}

// ─── Spinner ──────────────────────────────────────────────────────────────────
function Spinner() {
  return <div style={{ width: 12, height: 12, borderRadius: '50%', border: '2px solid rgba(0,0,0,0.3)', borderTopColor: '#000', animation: 'spin 0.7s linear infinite', flexShrink: 0 }} />
}

// ─── Payment method toggle chip ───────────────────────────────────────────────
function PaymentChip({ method, selected, onToggle }: { method: string; selected: boolean; onToggle: () => void }) {
  const [hovered, setHovered] = useState(false)
  return (
    <label
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      style={{
        display: 'inline-flex', alignItems: 'center', gap: '6px',
        padding: '7px 14px', borderRadius: '99px', cursor: 'pointer',
        background: selected ? 'rgba(200,162,0,0.12)' : hovered ? 'rgba(255,255,255,0.04)' : 'transparent',
        border: `1px solid ${selected ? 'rgba(200,162,0,0.45)' : hovered ? 'rgba(255,255,255,0.12)' : 'rgba(255,255,255,0.07)'}`,
        color: selected ? '#FFD700' : hovered ? '#9ca3af' : '#6b7280',
        fontSize: '12px', fontWeight: '700', fontFamily: "'Inter', sans-serif",
        transition: 'all 0.22s ease',
        boxShadow: selected ? '0 0 12px rgba(200,162,0,0.18)' : 'none',
      }}
    >
      <input type="checkbox" checked={selected} onChange={onToggle} style={{ display: 'none' }} />
      {selected && <span style={{ width: 6, height: 6, borderRadius: '50%', background: '#FFD700', display: 'inline-block', boxShadow: '0 0 6px rgba(255,215,0,0.8)' }} />}
      {method}
    </label>
  )
}

// ─── Section divider ──────────────────────────────────────────────────────────
function SDivider({ label }: { label: string }) {
  return (
    <div style={{ display: 'flex', alignItems: 'center', gap: '12px', margin: '24px 0 16px' }}>
      <div style={{ flex: 1, height: '1px', background: 'rgba(255,255,255,0.05)' }} />
      <span style={{ color: '#374151', fontSize: '9px', fontWeight: '700', letterSpacing: '0.14em', textTransform: 'uppercase', fontFamily: "'Inter', sans-serif", whiteSpace: 'nowrap' }}>{label}</span>
      <div style={{ flex: 1, height: '1px', background: 'rgba(255,255,255,0.05)' }} />
    </div>
  )
}

// ─── Detail Modal ─────────────────────────────────────────────────────────────
function DetailModal({ listing, userProfile, onClose, onBuy, buyingId }: {
  listing: any; userProfile: any; onClose: () => void
  onBuy: (item: any) => void; buyingId: string | null
}) {
  const isOwner = listing.seller_id === userProfile?.id
  const isBuying = buyingId === listing.id
  const [btnHovered, setBtnHovered] = useState(false)

  return (
    <div
      onClick={onClose}
      style={{
        position: 'fixed', inset: 0, zIndex: 1000,
        background: 'rgba(0,0,0,0.85)', backdropFilter: 'blur(8px)',
        display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '20px',
        animation: 'fadeIn 0.2s ease both',
      }}
    >
      <div
        onClick={e => e.stopPropagation()}
        style={{
          background: 'rgba(10,10,16,0.98)', backdropFilter: 'blur(40px)',
          border: '1px solid rgba(200,162,0,0.2)', borderRadius: '24px',
          maxWidth: '520px', width: '100%', maxHeight: '90vh', overflow: 'auto',
