              <div style={{ color: '#4b5563', fontSize: '10px', fontWeight: '700', letterSpacing: '0.1em', textTransform: 'uppercase', fontFamily: "'Inter', sans-serif", marginBottom: '4px' }}>Total Price</div>
              <div style={{
                fontSize: '34px', fontWeight: '900', letterSpacing: '-0.05em',
                background: 'linear-gradient(135deg, #c8a200, #FFD700)',
                WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent', backgroundClip: 'text',
                fontFamily: "'Inter', sans-serif", lineHeight: 1,
