            </div>
            <button
              onMouseEnter={() => setBtnHovered(true)}
              onMouseLeave={() => setBtnHovered(false)}
              onClick={() => { onClose(); onBuy(listing) }}
              disabled={isOwner || isBuying}
              style={{
                padding: '13px 30px', borderRadius: '14px', border: 'none',
                background: isOwner ? 'rgba(255,255,255,0.04)' : isBuying ? 'rgba(200,162,0,0.4)'
                  : btnHovered ? 'linear-gradient(135deg, #c8a200, #FFD700)' : 'linear-gradient(135deg, #b89200, #d4a500)',
                color: isOwner ? '#374151' : '#0a0a0a',
                fontSize: '14px', fontWeight: '800', letterSpacing: '0.03em',
                cursor: isOwner ? 'not-allowed' : 'pointer', fontFamily: "'Inter', sans-serif",
                transform: btnHovered && !isOwner ? 'scale(1.04) translateY(-1px)' : 'scale(1)',
                boxShadow: btnHovered && !isOwner ? '0 0 28px rgba(200,162,0,0.5), 0 6px 20px rgba(200,162,0,0.3)' : 'none',
                transition: 'all 0.25s cubic-bezier(0.4,0,0.2,1)', whiteSpace: 'nowrap',
                display: 'inline-flex', alignItems: 'center', gap: '7px',
              }}
            >
              {isOwner ? 'Your Item' : isBuying ? <><Spinner />Processing…</> : '🛒 Buy Now'}
            </button>
          </div>
        </div>
      </div>
    </div>
  )
}

// ─── Create listing form ──────────────────────────────────────────────────────
