  onCancel: () => void; togglePayment: (m: string) => void
}) {
  return (
    <div style={{
      background: 'rgba(10,10,16,0.96)', backdropFilter: 'blur(32px)',
      border: '1px solid rgba(200,162,0,0.18)', borderRadius: '24px',
