      animation: 'fadeSlideDown 0.35s cubic-bezier(0.4,0,0.2,1) both',
    }}>
      <div style={{ height: '1px', background: 'linear-gradient(90deg, transparent, rgba(200,162,0,0.4), transparent)' }} />
      <div style={{ padding: '32px' }}>
        {/* Form header */}
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '4px' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
            <div style={{
              width: 36, height: 36, borderRadius: '10px',
              background: 'rgba(200,162,0,0.1)', border: '1px solid rgba(200,162,0,0.2)',
              display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '16px',
            }}>🏷️</div>
            <div>
              <div style={{ color: '#c8a200', fontSize: '10px', fontWeight: '700', letterSpacing: '0.1em', textTransform: 'uppercase', fontFamily: "'Inter', sans-serif" }}>Seller Hub</div>
              <div style={{ color: 'white', fontSize: '17px', fontWeight: '800', letterSpacing: '-0.02em', fontFamily: "'Inter', sans-serif" }}>Create Listing</div>
            </div>
          </div>
          <button
            onClick={onCancel}
            style={{
              display: 'inline-flex', alignItems: 'center', gap: '6px',
              padding: '8px 14px', borderRadius: '10px',
              background: 'rgba(239,68,68,0.08)', border: '1px solid rgba(239,68,68,0.2)',
              color: '#f87171', fontSize: '12px', fontWeight: '700',
              cursor: 'pointer', fontFamily: "'Inter', sans-serif", transition: 'all 0.2s',
            }}
            onMouseEnter={e => { e.currentTarget.style.background = 'rgba(239,68,68,0.15)' }}
            onMouseLeave={e => { e.currentTarget.style.background = 'rgba(239,68,68,0.08)' }}
          >✕ Cancel</button>
        </div>

        <form onSubmit={onSubmit}>
          <SDivider label="Product Details" />
          <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
