            <FTextarea value={formData.description} onChange={(e: any) => setFormData({ ...formData, description: e.target.value })} placeholder="Description (optional)" />
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
              <FInput value={formData.price} onChange={(e: any) => setFormData({ ...formData, price: e.target.value })} placeholder="Price (PKR) *" type="number" step="0.01" min="0.01" required />
              <FSelect value={formData.condition} onChange={(e: any) => setFormData({ ...formData, condition: e.target.value })}>
                <option value="New">🆕 New</option>
                <option value="Like New">✨ Like New</option>
                <option value="Good">👍 Good</option>
                <option value="Fair">👌 Fair</option>
