// ─── Main export ──────────────────────────────────────────────────────────────
export const Marketplace: React.FC = () => {
  const [listings, setListings]             = useState<any[]>([])
  const [loading, setLoading]               = useState(true)
  const [currentUser, setCurrentUser]       = useState<any>(null)
  const [userProfile, setUserProfile]       = useState<any>(null)
  const [showCreateForm, setShowCreateForm] = useState(false)
  const [buyingId, setBuyingId]             = useState<string | null>(null)
  const [selectedListing, setSelectedListing] = useState<any>(null)
  const [showDetail, setShowDetail]         = useState(false)
  const [error, setError]                   = useState('')

  const [formData, setFormData] = useState({
    item_name: '', description: '', price: '', condition: 'Good',
    category: '', seller_phone: '', payment_methods: ['JazzCash', 'EasyPaisa'] as string[],
  })

  useEffect(() => { loadUserAndListings() }, [])

  const loadUserAndListings = async () => {
    setLoading(true); setError('')
    const { data: { user } } = await supabase.auth.getUser()
    setCurrentUser(user)
    if (user) {
      const { data: profile, error: profileError } = await supabase.from('users').select('*').eq('id', user.id).single()
      if (profileError) {
        const { error: insertError } = await supabase.from('users').insert({
          id: user.id, full_name: user.user_metadata?.full_name || user.email?.split('@')[0] || 'User',
          email: user.email, role: 'Player', status: 'active',
        })
        if (!insertError) {
          const { data: newProfile } = await supabase.from('users').select('*').eq('id', user.id).single()
          setUserProfile(newProfile)
        }
      } else { setUserProfile(profile) }
    }
    const { data, error: listingsError } = await supabase.from('marketplace').select('*').eq('status', 'AVAILABLE').order('created_at', { ascending: false })
    if (!listingsError) setListings(data || [])
    setLoading(false)
  }

  const handleCreateListing = async (e: React.FormEvent) => {
    e.preventDefault(); setError('')
    if (!currentUser || !userProfile) { setError('Please login first'); return }
    const price = parseFloat(formData.price)
    if (isNaN(price) || price <= 0) { setError('Please enter a valid price'); return }
    if (!formData.item_name.trim()) { setError('Please enter an item name'); return }
    if (!formData.seller_phone.trim()) { setError('Please enter your phone number'); return }

    const { error: insertError } = await supabase.from('marketplace').insert({
      seller_id: userProfile.id, item_name: formData.item_name.trim(),
      description: formData.description.trim(), price,
      condition: formData.condition, category: formData.category.trim() || 'Other',
      seller_phone: formData.seller_phone.trim(),
      payment_methods: formData.payment_methods, status: 'AVAILABLE',
    })
    if (insertError) {
      setError('Failed to create listing: ' + insertError.message)
    } else {
      alert('✅ Listing created successfully!')
      setShowCreateForm(false)
      setFormData({ item_name: '', description: '', price: '', condition: 'Good', category: '', seller_phone: '', payment_methods: ['JazzCash', 'EasyPaisa'] })
      loadUserAndListings()
    }
  }

  const handleBuy = async (listing: any) => {
    if (!currentUser || !userProfile) { alert('⚠️ Please login first'); return }
    if (listing.seller_id === userProfile.id) { alert('⚠️ You cannot buy your own item'); return }
    if (listing.status !== 'AVAILABLE') { alert('⚠️ This item is no longer available'); return }
    setBuyingId(listing.id)
    const paymentMethods = listing.payment_methods || ['JazzCash', 'EasyPaisa']
    const phoneNumber = listing.seller_phone || 'Not provided'
    const confirmMessage = `Buy "${listing.item_name}" for $${listing.price}?\n\n📱 Seller Contact: ${phoneNumber}\n💳 Payment Methods: ${paymentMethods.join(', ')}\n\nContact the seller to arrange payment.\nClick OK to confirm purchase.`
    if (!window.confirm(confirmMessage)) { setBuyingId(null); return }
    const { error: updateError } = await supabase.from('marketplace').update({ status: 'SOLD' }).eq('id', listing.id)
    if (updateError) { alert('❌ Purchase failed: ' + updateError.message); setBuyingId(null); return }
    await supabase.from('purchases').insert({ listing_id: listing.id, buyer_id: userProfile.id })
    alert(`✅ Purchase confirmed for "${listing.item_name}"!\n\n📱 Contact seller: ${phoneNumber}\n💳 Pay via: ${paymentMethods.join(', ')}`)
    setBuyingId(null); loadUserAndListings()
  }

  const togglePaymentMethod = (method: string) => {
    setFormData(prev => {
      const methods = prev.payment_methods.includes(method)
        ? prev.payment_methods.filter(m => m !== method)
        : [...prev.payment_methods, method]
      return { ...prev, payment_methods: methods }
    })
  }

  const openDetail = (listing: any) => { setSelectedListing(listing); setShowDetail(true) }
  const closeDetail = () => { setShowDetail(false); setSelectedListing(null) }

  return (
    <div style={{
      minHeight: '100vh', background: '#0D0D0F', color: 'white',
      fontFamily: "'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif",
      position: 'relative', overflowX: 'hidden',
    }}>
      {/* ── Ambient ── */}
      <div style={{ position: 'fixed', inset: 0, zIndex: 0, pointerEvents: 'none',
        background: 'radial-gradient(ellipse 70% 45% at 50% -5%, rgba(200,162,0,0.06) 0%, transparent 65%)' }} />
      <div style={{ position: 'fixed', top: '25%', right: '-18%', width: '650px', height: '650px',
        borderRadius: '50%', background: 'rgba(200,162,0,0.025)', filter: 'blur(120px)',
        zIndex: 0, pointerEvents: 'none', animation: 'floatBlob 15s ease-in-out infinite' }} />
      <div style={{ position: 'fixed', bottom: '-12%', left: '-14%', width: '600px', height: '600px',
        borderRadius: '50%', background: 'rgba(59,130,246,0.02)', filter: 'blur(110px)',
        zIndex: 0, pointerEvents: 'none', animation: 'floatBlob 20s ease-in-out infinite 5s' }} />

      <div style={{ maxWidth: '1060px', margin: '0 auto', padding: '40px 24px 80px', position: 'relative', zIndex: 1 }}>

        {/* ══════════ HERO ══════════ */}
        <section style={{ marginBottom: '40px', animation: 'fadeSlideUp 0.55s ease both' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end', flexWrap: 'wrap', gap: '20px' }}>
            <div>
              {/* Eyebrow */}
              <div style={{
                display: 'inline-flex', alignItems: 'center', gap: '8px',
                padding: '5px 14px 5px 8px', background: 'rgba(200,162,0,0.08)',
                border: '1px solid rgba(200,162,0,0.18)', borderRadius: '99px', marginBottom: '18px',
              }}>
                <span style={{ display: 'inline-flex', alignItems: 'center', justifyContent: 'center', width: 18, height: 18, borderRadius: '50%', background: 'rgba(200,162,0,0.2)', fontSize: 10 }}>🛒</span>
                <span style={{ color: '#c8a200', fontSize: '11px', fontWeight: '700', letterSpacing: '0.1em', textTransform: 'uppercase', fontFamily: "'Inter', sans-serif" }}>Sports Marketplace</span>
              </div>
              <h1 style={{ fontSize: 'clamp(28px,4.5vw,48px)', fontWeight: '900', letterSpacing: '-0.04em', lineHeight: 1.05, color: 'white', margin: '0 0 10px', fontFamily: "'Inter', sans-serif" }}>
                Buy & Sell<br />
                <span style={{ background: 'linear-gradient(135deg, #c8a200 0%, #FFD700 50%, #e8b800 100%)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent', backgroundClip: 'text' }}>
                  Sports Gear
                </span>
              </h1>
              <p style={{ color: '#4b5563', fontSize: '15px', margin: 0, lineHeight: 1.5, maxWidth: '380px', fontFamily: "'Inter', sans-serif" }}>
                Quality equipment from fellow athletes — pay via JazzCash, EasyPaisa, and more.
              </p>
              {/* Live stats */}
              {!loading && (
                <div style={{ display: 'flex', gap: '12px', marginTop: '22px', flexWrap: 'wrap' }}>
                  {[
                    { label: 'Listings', value: listings.length, icon: '📦' },
                    { label: 'Categories', value: new Set(listings.map(l => l.category).filter(Boolean)).size, icon: '🏷️' },
                  ].map((s, i) => (
                    <div key={s.label} style={{
                      display: 'inline-flex', alignItems: 'center', gap: '10px',
                      padding: '8px 16px', borderRadius: '12px',
                      background: 'rgba(255,255,255,0.03)', border: '1px solid rgba(255,255,255,0.06)',
                      animation: `fadeSlideUp 0.5s ease ${200 + i * 55}ms both`,
                    }}>
                      <span style={{ fontSize: '14px' }}>{s.icon}</span>
                      <div>
                        <div style={{ fontSize: '18px', fontWeight: '800', color: 'white', lineHeight: 1, fontFamily: "'Inter', sans-serif", letterSpacing: '-0.03em' }}>{s.value}</div>
                        <div style={{ fontSize: '9px', color: '#4b5563', fontWeight: '700', letterSpacing: '0.09em', textTransform: 'uppercase', fontFamily: "'Inter', sans-serif" }}>{s.label}</div>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>

            {/* Sell button */}
            <SellButton active={showCreateForm} onToggle={() => setShowCreateForm(f => !f)} />
          </div>
        </section>

        {/* Error */}
        {error && (
          <div style={{
            padding: '14px 20px', borderRadius: '14px', marginBottom: '20px',
            background: 'rgba(239,68,68,0.08)', border: '1px solid rgba(239,68,68,0.2)',
            color: '#f87171', fontSize: '13px', fontWeight: '600',
            display: 'flex', alignItems: 'center', gap: '10px',
            animation: 'fadeSlideUp 0.3s ease both', fontFamily: "'Inter', sans-serif",
          }}>
            <span>✕</span>{error}
          </div>
        )}

        {/* ══════════ FORM ══════════ */}
        {showCreateForm && (
          <CreateForm
            formData={formData} setFormData={setFormData}
            onSubmit={handleCreateListing} onCancel={() => setShowCreateForm(false)}
            togglePayment={togglePaymentMethod}
          />
        )}

        {/* ══════════ LISTINGS ══════════ */}
        {loading ? (
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(260px, 1fr))', gap: '16px' }}>
            {[0,1,2,3,5,6].map(i => <SkeletonCard key={i} i={i} />)}
          </div>
        ) : listings.length === 0 ? (
          <div style={{
            background: 'rgba(12,12,18,0.9)', backdropFilter: 'blur(32px)',
            border: '1px solid rgba(255,255,255,0.05)', borderRadius: '24px',
            padding: '80px 40px', textAlign: 'center', position: 'relative', overflow: 'hidden',
            animation: 'fadeSlideUp 0.5s ease both',
          }}>
            <div style={{ position: 'absolute', top: '50%', left: '50%', transform: 'translate(-50%,-50%)', width: 300, height: 300, borderRadius: '50%', background: 'rgba(200,162,0,0.03)', filter: 'blur(60px)', pointerEvents: 'none' }} />
            <div style={{ position: 'relative' }}>
              <div style={{ display: 'inline-flex', alignItems: 'center', justifyContent: 'center', width: 72, height: 72, borderRadius: '20px', background: 'rgba(200,162,0,0.08)', border: '1px solid rgba(200,162,0,0.15)', fontSize: '36px', marginBottom: '20px' }}>🛒</div>
              <h3 style={{ fontSize: '20px', fontWeight: '800', color: 'white', margin: '0 0 8px', letterSpacing: '-0.02em', fontFamily: "'Inter', sans-serif" }}>No listings yet</h3>
              <p style={{ color: '#4b5563', fontSize: '14px', margin: '0 0 28px', lineHeight: 1.5, fontFamily: "'Inter', sans-serif" }}>Be the first to list a piece of sports equipment!</p>
              <button onClick={() => setShowCreateForm(true)} style={{
                display: 'inline-flex', alignItems: 'center', gap: '8px',
                padding: '12px 28px', background: 'linear-gradient(135deg, #c8a200, #FFD700)',
                color: '#0a0a0a', fontWeight: '800', fontSize: '13px', letterSpacing: '0.04em',
                textTransform: 'uppercase', borderRadius: '12px', border: 'none', cursor: 'pointer',
                boxShadow: '0 4px 24px rgba(200,162,0,0.3)', fontFamily: "'Inter', sans-serif",
              }}>
                🏷️ Sell First Item
              </button>
            </div>
          </div>
        ) : (
          <div>
            {/* Section label */}
            <div style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '20px' }}>
              <div style={{ width: 16, height: 1, background: 'rgba(200,162,0,0.4)' }} />
              <span style={{ color: '#374151', fontSize: '10px', fontWeight: '700', letterSpacing: '0.14em', textTransform: 'uppercase', fontFamily: "'Inter', sans-serif", whiteSpace: 'nowrap' }}>
                {listings.length} Item{listings.length !== 1 ? 's' : ''} Available
              </span>
              <div style={{ flex: 1, height: 1, background: 'rgba(255,255,255,0.04)' }} />
            </div>
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(270px, 1fr))', gap: '16px' }}>
              {listings.map((item, i) => (
                <ListingCard
                  key={item.id} item={item} index={i}
                  isOwner={item.seller_id === userProfile?.id}
                  isBuying={buyingId === item.id}
                  onBuy={handleBuy} onOpen={openDetail}
                />
              ))}
            </div>
          </div>
        )}

        {/* Footer */}
        <div style={{ marginTop: '60px', display: 'flex', justifyContent: 'center' }}>
          <div style={{
            display: 'inline-flex', alignItems: 'center', gap: '10px',
            padding: '8px 20px', background: 'rgba(255,255,255,0.02)',
            border: '1px solid rgba(255,255,255,0.04)', borderRadius: '99px',
          }}>
            <span style={{ width: 6, height: 6, borderRadius: '50%', background: '#22c55e', boxShadow: '0 0 6px rgba(34,197,94,0.6)', display: 'inline-block', animation: 'pulse 2s ease-in-out infinite' }} />
            <span style={{ color: '#374151', fontSize: '11px', fontWeight: '500', letterSpacing: '0.06em', fontFamily: "'Inter', sans-serif" }}>TEAMSYNK · MARKETPLACE · SECURE TRADING</span>
          </div>
        </div>
      </div>

      {/* ── Detail Modal ── */}
      {showDetail && selectedListing && (
        <DetailModal
          listing={selectedListing} userProfile={userProfile}
          onClose={closeDetail} onBuy={handleBuy} buyingId={buyingId}
        />
      )}

      {/* ── Keyframes ── */}
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800;900&display=swap');
        * { box-sizing: border-box; }
        input::placeholder, textarea::placeholder { color: #374151; }
        select option { background: #111118; color: #f9fafb; }
        @keyframes spin          { from{transform:rotate(0deg)} to{transform:rotate(360deg)} }
        @keyframes fadeSlideUp   { from{opacity:0;transform:translateY(18px)} to{opacity:1;transform:translateY(0)} }
        @keyframes fadeSlideDown { from{opacity:0;transform:translateY(-12px)} to{opacity:1;transform:translateY(0)} }
        @keyframes floatBlob     { 0%,100%{transform:translateY(0) scale(1)} 50%{transform:translateY(-28px) scale(1.04)} }
        @keyframes pulse         { 0%,100%{opacity:0.6;transform:scale(1)} 50%{opacity:1;transform:scale(1.1)} }
        @keyframes shimmer       { 0%{opacity:0.4} 50%{opacity:0.9} 100%{opacity:0.4} }
        @keyframes shimmerSweep  { 0%{left:-100%} 60%{left:150%} 100%{left:150%} }
        @keyframes fadeIn        { from{opacity:0} to{opacity:1} }
        @keyframes modalIn       { from{opacity:0;transform:scale(0.94) translateY(10px)} to{opacity:1;transform:scale(1) translateY(0)} }
        ::-webkit-scrollbar       { width: 6px; }
        ::-webkit-scrollbar-track { background: #0D0D0F; }
        ::-webkit-scrollbar-thumb { background: rgba(200,162,0,0.3); border-radius: 3px; }
      `}</style>
    </div>
  )
}

// ─── Sell button ──────────────────────────────────────────────────────────────
function SellButton({ active, onToggle }: { active: boolean; onToggle: () => void }) {
  const [hovered, setHovered] = useState(false)
  return (
    <button
      onClick={onToggle}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      style={{
        display: 'inline-flex', alignItems: 'center', gap: '7px',
        padding: '12px 24px', borderRadius: '14px', border: 'none', cursor: 'pointer',
        background: active
          ? hovered ? 'rgba(239,68,68,0.18)' : 'rgba(239,68,68,0.1)'
          : hovered ? 'linear-gradient(135deg, #c8a200, #FFD700)' : 'linear-gradient(135deg, #b89200, #d4a500)',
        color: active ? '#f87171' : '#0a0a0a',
        border2: active ? '1px solid rgba(239,68,68,0.3)' : 'none',
        fontSize: '13px', fontWeight: '800', letterSpacing: '0.03em', fontFamily: "'Inter', sans-serif",
        transform: hovered && !active ? 'scale(1.04) translateY(-1px)' : 'scale(1)',
        boxShadow: hovered && !active ? '0 0 28px rgba(200,162,0,0.5), 0 4px 16px rgba(200,162,0,0.3)' : 'none',
        transition: 'all 0.25s cubic-bezier(0.4,0,0.2,1)', whiteSpace: 'nowrap', flexShrink: 0,
        ...(active ? { border: '1px solid rgba(239,68,68,0.3)' } : {}),
      } as any}
    >
      {active ? '✕ Cancel' : '🏷️ Sell Item'}
    </button>
  )
}
